        self.iv = iv
        self.salt = salt
    }
}



extension WrappedBlob: Equatable, Hashable {
    public static func ==(lhs: WrappedBlob, rhs: WrappedBlob) -> Bool {
        if lhs.wrappedKey != rhs.wrappedKey {
            return false
        }
        if lhs.iv != rhs.iv {
            return false
        }
        if lhs.salt != rhs.salt {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(wrappedKey)
        hasher.combine(iv)
        hasher.combine(salt)
    }
}


