@_documentation(visibility: private)
#endif
fileprivate struct FfiConverterOptionString: FfiConverterRustBuffer {
    typealias SwiftType = String?

    public static func write(_ value: SwiftType, into buf: inout [UInt8]) {
        guard let value = value else {
            writeInt(&buf, Int8(0))
            return
        }
        writeInt(&buf, Int8(1))
        FfiConverterString.write(value, into: &buf)
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> SwiftType {
        switch try readInt(&buf) as Int8 {
        case 0: return nil
        case 1: return try FfiConverterString.read(from: &buf)
        default: throw UniffiInternalError.unexpectedOptionalTag
        }
    }
}

private enum InitializationResult {
    case ok
    case contractVersionMismatch
    case apiChecksumMismatch
}
// Use a global variable to perform the versioning checks. Swift ensures that
// the code inside is only computed once.
private var initializationResult: InitializationResult = {
    // Get the bindings contract version from our ComponentInterface
    let bindings_contract_version = 26
    // Get the scaffolding contract version by calling the into the dylib
    let scaffolding_contract_version = ffi_braird_core_uniffi_contract_version()
    if bindings_contract_version != scaffolding_contract_version {
        return InitializationResult.contractVersionMismatch
    }
    if (uniffi_braird_core_checksum_method_vault_content_tag() != 23104) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_braird_core_checksum_method_vault_decrypt_note() != 2957) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_braird_core_checksum_method_vault_encrypt_note() != 22447) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_braird_core_checksum_method_vault_open_bytes() != 24917) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_braird_core_checksum_method_vault_pin_wrap() != 28802) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_braird_core_checksum_method_vault_rewrap() != 61446) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_braird_core_checksum_method_vault_seal_bytes() != 63933) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_braird_core_checksum_method_vault_wrap_with_prf() != 28929) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_braird_core_checksum_constructor_vault_generate() != 65080) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_braird_core_checksum_constructor_vault_redeem_pin_transfer() != 25070) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_braird_core_checksum_constructor_vault_unlock() != 13169) {
        return InitializationResult.apiChecksumMismatch
    }

    return InitializationResult.ok
}()

private func uniffiEnsureInitialized() {
    switch initializationResult {
    case .ok:
        break
    case .contractVersionMismatch:
        fatalError("UniFFI contract version mismatch: try cleaning and rebuilding your project")
    case .apiChecksumMismatch:
        fatalError("UniFFI API checksum mismatch: try cleaning and rebuilding your project")
    }
}

